.darma-loader-darma-custom-661-loader-wrapper {--loader-secondary-color: #471eec;
  --loader-bg: #111827;

  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 180px;
  height: 180px;
  font-family: "Inter", sans-serif;
  font-size: 1.2em;
  font-weight: 300;
  color: var(--loader-color, #ad5fff);
  border-radius: 50%;
  background-color: transparent;
  user-select: none;
}

.darma-loader-darma-custom-661 {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  aspect-ratio: 1 / 1;
  border-radius: 50%;
  background-color: transparent;
  animation: darma-loader-darma-custom-661-loader-rotate 2s linear infinite;
  z-index: 0;
}

@keyframes darma-loader-darma-custom-661-loader-rotate {
  0% {
    transform: rotate(90deg);
    box-shadow:
      0 10px 20px 0 currentColor inset,
      0 20px 30px 0 #ad5fff inset,
      0 60px 60px 0 #471eec inset;
  }
  50% {
    transform: rotate(270deg);
    box-shadow:
      0 10px 20px 0 currentColor inset,
      0 20px 10px 0 #d60a47 inset,
      0 40px 60px 0 #311e80 inset;
  }
  100% {
    transform: rotate(450deg);
    box-shadow:
      0 10px 20px 0 currentColor inset,
      0 20px 30px 0 #ad5fff inset,
      0 60px 60px 0 #471eec inset;
  }
}

.darma-loader-darma-custom-661-loader-letter {
  display: inline-block;
  opacity: 0.4;
  transform: translateY(0);
  animation: darma-loader-darma-custom-661-loader-letter-anim 2s infinite;
  z-index: 1;
  border-radius: 50ch;
  border: none;
}

.darma-loader-darma-custom-661-loader-letter:nth-child(1) {
  animation-delay: 0s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(2) {
  animation-delay: 0.1s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(3) {
  animation-delay: 0.2s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(4) {
  animation-delay: 0.3s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(5) {
  animation-delay: 0.4s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(6) {
  animation-delay: 0.5s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(7) {
  animation-delay: 0.6s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(8) {
  animation-delay: 0.7s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(9) {
  animation-delay: 0.8s;
}
.darma-loader-darma-custom-661-loader-letter:nth-child(10) {
  animation-delay: 0.9s;
}

@keyframes darma-loader-darma-custom-661-loader-letter-anim {
  0%,
  100% {
    opacity: 0.4;
    transform: translateY(0);
  }
  20% {
    opacity: 1;
    transform: scale(1.15);
  }
  40% {
    opacity: 0.7;
    transform: translateY(0);
  }
}

.darma-loader-darma-custom-057 {
  --s: 25px;

  --_d: calc(0.353*var(--s));
  width: calc(var(--s) + var(--_d));
  aspect-ratio: 1;
  clip-path: polygon(var(--_d) 0,100% 0,100% calc(100% - var(--_d)),calc(100% - var(--_d)) 100%,0 100%,0 var(--_d));
  background:
    conic-gradient(from -90deg at var(--s) var(--_d),
     #fff 135deg,#666 0 270deg,#aaa 0);
  animation: darma-loader-darma-custom-057-l1 1s infinite cubic-bezier(0.5,300,0.5,-300);
}
@keyframes darma-loader-darma-custom-057-l1{
  50%,100% {transform:translateY(0.1px)}
}

/* Prior to using this loader, please ensure that you have set a background image or background color, as the text is transparent and not designed with a solid color. */
.darma-loader-darma-custom-648 {color: var(--loader-color, #111827);
  --loader-secondary-color: #64748b;
  --loader-bg: #f8fafc;

  --ANIMATION-DELAY-MULTIPLIER: 70ms;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: row;
  justify-content: center;
  align-items: center;
  overflow: hidden;
}
.darma-loader-darma-custom-648 span {
  padding: 0;
  margin: 0;
  letter-spacing: -5rem;
  animation-delay: 0s;
  transform: translateY(4rem);
  animation: darma-loader-darma-custom-648-hideAndSeek 1s alternate infinite cubic-bezier(0.86, 0, 0.07, 1);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-l {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 0);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-o {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 1);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-a {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 2);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-d {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 3);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-ispan {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 4);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-n {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 5);
}
.darma-loader-darma-custom-648 .darma-loader-darma-custom-648-g {
  animation-delay: calc(var(--ANIMATION-DELAY-MULTIPLIER) * 6);
}
.darma-loader-darma-custom-648-letter {
  width: fit-content;
  height: 3rem;
}
.darma-loader-darma-custom-648-i {
  margin-inline: 5px;
}
@keyframes darma-loader-darma-custom-648-hideAndSeek {
  0% {
    transform: translateY(4rem);
  }
  100% {
    transform: translateY(0rem);
  }
}

