  font-size: 1em;
  padding: 1.5em 1em;
  width: 12em;
  box-shadow: 0 4px 8px color-mix(in srgb, var(--loader-color, #22c55e) 45%, transparent);
  border-radius: 4px;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
}

